import * as mongodb from "mongodb";
import { User } from "./models/user";
import { CardCollection, Cards, LikedCollection } from "./models/card";

export const collections: {
    users?: mongodb.Collection<User>;
    cardCollections?: mongodb.Collection<CardCollection>;
    likedCollections?: mongodb.Collection<LikedCollection>;
    cards?: mongodb.Collection<Cards>;
} = {};

export async function connectToDatabase(uri: string) {
    const client = new mongodb.MongoClient(uri);
    await client.connect();

    const db = client.db("nice_cards");

    const usersCollection = db.collection<User>("users");
    const cardCollectionsCollection = db.collection<CardCollection>("cardCollections");
    const likedCollectionsCollection = db.collection<LikedCollection>("likedCollections");
    const cardsCollection = db.collection<Cards>("cards");

    collections.users = usersCollection;
    collections.cardCollections = cardCollectionsCollection;
    collections.likedCollections = likedCollectionsCollection;
    collections.cards = cardsCollection;
}

import cookieParser from "cookie-parser";
import * as dotenv from "dotenv";
import express from "express";
import session from "express-session";
import passport from "passport";
import { configureCors } from "./config/cors";
import { configurePassport } from "./config/passport";
import { connectToDatabase } from "./database";
import { apiRouter } from "./routes";

// Load environment variables
dotenv.config();
const { ATLAS_URI, SESSION_SECRET } = process.env;

if (!ATLAS_URI) {
    console.error("No ATLAS_URI environment variable has been defined in .env");
    process.exit(1);
}

connectToDatabase(ATLAS_URI)
    .then(() => {
        const app = express();

        // Middleware
        configureCors(app);
        app.use(cookieParser());
        app.use(
            session({
                secret: SESSION_SECRET!,
                resave: false,
                saveUninitialized: false,
            })
        );

        app.use(passport.initialize());
        app.use(passport.session());

        configurePassport(passport);

        // start the Express server
        app.listen(5200, () => {
            console.log(`Server running at http://localhost:5200...`);
        });

        app.use("/api", apiRouter);
    })
    .catch((error) => console.error(error));

import * as argon2 from "argon2";
import { Strategy as LocalStrategy } from "passport-local";
import { Strategy as GoogleStrategy } from "passport-google-oauth20";
import { Strategy as FacebookStrategy } from "passport-facebook";
import { collections } from "../database";
import { PassportStatic } from "passport";
import { createPublicUser, User } from "../models/user";
import * as dotenv from "dotenv";

dotenv.config();

export function configurePassport(passport: PassportStatic) {
    passport.use(
        new LocalStrategy(
            {
                usernameField: "email",
                passwordField: "password",
            },
            async (email, password, done) => {
                try {
                    const user = await collections.users?.findOne({ email });

                    if (!user) {
                        return done(
                            {
                                errorMessage: "Invalid credentials",
                            },
                            false
                        );
                    }

                    if (await argon2.verify(user.password!, password)) {
                        return done(null, createPublicUser(user));
                    } else {
                        return done(
                            {
                                errorMessage: "Invalid credentials",
                            },
                            false
                        );
                    }
                } catch (error) {
                    return done(error);
                }
            }
        )
    );

    passport.use(
        new GoogleStrategy(
            {
                clientID: process.env.GOOGLE_CLIENT_ID!,
                clientSecret: process.env.GOOGLE_CLIENT_SECRET!,
                callbackURL: "http://localhost:5200/api/auth/google/callback",
            },
            async (accessToken, refreshToken, profile, done) => {
                try {
                    // Check if the user already exists
                    let user = await collections.users?.findOne({ googleId: profile.id });

                    if (!user) {
                        // Create a new user if not found
                        const newUser: User = {
                            googleId: profile.id,
                            email: profile.emails?.[0].value || "",
                            role: "user",
                            profile: {
                                username: profile.displayName,
                                avatarUrl: profile.photos?.[0].value,
                                bio: "",
                                createdAt: new Date().toISOString(),
                            },
                        };

                        const result = await collections.users?.insertOne(newUser);

                        if (result?.acknowledged) {
                            user = { ...newUser, _id: result.insertedId };
                            return done(null, createPublicUser(newUser));
                        } else {
                            return done(null, false, {
                                message: "Couldn't create user",
                            });
                        }
                    }

                    return done(null, createPublicUser(user));
                } catch (err) {
                    done(err);
                }
            }
        )
    );

    passport.use(
        new FacebookStrategy(
            {
                clientID: process.env.FACEBOOK_CLIENT_ID!,
                clientSecret: process.env.FACEBOOK_CLIENT_SECRET!,
                callbackURL: "http://localhost:5200/api/auth/facebook/callback",
                profileFields: ["id", "email", "name", "picture.type(large)"],
            },
            async (accessToken, refreshToken, profile, done) => {
                try {
                    // Check if the user already exists
                    let user = await collections.users?.findOne({ facebookId: profile.id });

                    if (!user) {
                        // Create a new user if not found
                        const newUser: User = {
                            facebookId: profile.id,
                            email: profile.emails?.[0].value || "",
                            role: "user",
                            profile: {
                                username:
                                    profile.displayName || `${profile.name?.givenName} ${profile.name?.familyName}`,
                                avatarUrl: profile.photos?.[0].value,
                                bio: "",
                                createdAt: new Date().toISOString(),
                            },
                        };

                        const result = await collections.users?.insertOne(newUser);

                        if (result?.acknowledged) {
                            return done(null, createPublicUser(newUser));
                        } else {
                            return done(null, false, {
                                message: "Couldn't create user",
                            });
                        }
                    }

                    return done(null, createPublicUser(user));
                } catch (err) {
                    done(err);
                }
            }
        )
    );

    passport.serializeUser((user: Express.User, done) => {
        done(null, user);
    });

    passport.deserializeUser((user: Express.User, done) => {
        done(null, user);
    });
}

import { Express } from "express";
import cors from "cors";

export function configureCors(app: Express) {
    const whitelist = ["*", "http://localhost:4200"];

    const corsOptions = {
        origin: (origin: string | undefined, callback: (err: Error | null, allowed?: boolean) => void) => {
            if (whitelist.indexOf(origin!) !== -1 || whitelist.includes("*")) {
                callback(null, true);
            } else {
                callback(new Error("Not allowed by CORS."));
            }
        },
        credentials: true,
    };

    app.use(cors(corsOptions));
}

import * as argon2 from "argon2";
import * as express from "express";
import passport from "passport";
import { collections } from "../database";
import { User } from "../models/user";

// Router for handling authentication throughout the app, using express sessions and passport (local, google, facebook)
export const authRouter = express.Router();
authRouter.use(express.json());

// Local signup
authRouter.post("/signup", async (req, res) => {
    try {
        const { email, username, password, passwordAgain } = req.body;

        // Validate input
        const existingUser = await collections.users?.findOne({
            $or: [{ "profile.username": username }, { email: email }],
        });

        if (existingUser) {
            if (existingUser.profile.username === username) {
                res.status(409).send({ errorMessage: "Username already taken" });
            } else {
                res.status(409).send({ errorMessage: "An account already exists with this email address" });
            }
            return;
        }

        if (password !== passwordAgain) {
            res.status(400).send({ errorMessage: "Provided passwords don't match" });
            return;
        }

        // But Norbo... why no salt?
        // https://github.com/ranisalt/node-argon2/wiki/Options#salt
        const hash = await argon2.hash(password);

        const user: User = {
            email: email,
            password: hash,
            role: "user",
            profile: {
                username: username,
                createdAt: new Date().toJSON(),
            },
        };

        const result = await collections?.users?.insertOne(user);

        if (result?.acknowledged) {
            res.status(200).send({ successMessage: "Succesfully signed up!" });
        } else {
            res.status(500).send({ errorMessage: "Sign up failed" });
        }
    } catch (error) {
        res.status(400).send({ errorMessage: "Something went wrong while trying to sign up" });
    }
});

authRouter.post("/login", (req, res, next) => {
    passport.authenticate("local", (error: string | null, user: User) => {
        if (error) {
            res.status(500).send(error);
        } else {
            req.login(user, (err: string | null) => {
                if (err) {
                    console.log(err);
                    res.status(500).send(err);
                } else {
                    res.status(200).send(user);
                }
            });
        }
    })(req, res, next);
});

