// Logout
authRouter.post("/logout", (req, res) => {
    if (!req.isAuthenticated()) {
        res.status(401).send({ errorMessage: "Not logged in" });
        return;
    }

    req.logout((err) => {
        if (err) return res.status(500).send({ errorMessage: "Error logging out" });
        res.status(200).send({});
    });
});

// Authentication check (mostly used by angulars route guard)
authRouter.get("/isAuthenticated", (req, res) => {
    if (req.isAuthenticated()) {
        res.status(200).send(true);
    } else {
        res.status(401).send(false);
    }
});

// Return information about the user in session
authRouter.get("/checkAuthStatus", (req, res) => {
    res.json({
        isAuthenticated: req.isAuthenticated(),
        user: req.isAuthenticated() ? req.user : null,
    });
});

// Used for authenticating endpoint on the server
export function isAuthenticated(req: express.Request, res: express.Response, next: express.NextFunction) {
    if (req.isAuthenticated()) return next();
    res.status(401).json({ message: "Unauthorized" });
}

import * as express from "express";
import { collections } from "../database";
import { isAuthenticated } from "./auth.routes";
import { User } from "../models/user";
import { CardCollection } from "../models/card";
import { ObjectId } from "mongodb";

// Responsible for the endpoints regarding a single card collection
export const cardCollectionRouter = express.Router();
cardCollectionRouter.use(express.json());

// Create new collection
cardCollectionRouter.post("/", isAuthenticated, async (req, res) => {
    try {
        const userId = (req.user as User)._id!;
        const { title, visibility } = req.body;

        const cardCollection: CardCollection = {
            creationDate: new Date().toISOString().substring(0, 10),
            title: title,
            summary: "",
            ownerId: userId,
            visibility: visibility,
        };

        const result = await collections?.cardCollections?.insertOne(cardCollection);

        if (result?.acknowledged) {
            const cardsResult = await collections?.cards?.insertOne({ _id: result.insertedId, cards: [] });

            if (!cardsResult?.acknowledged) {
                res.status(500).send("Failed to create new card collection");
            } else {
                res.status(200).send(result.insertedId);
            }
        } else {
            res.status(500).send("Failed to create new card collection");
        }
    } catch (error) {
        res.status(404).send("Failed to create new card collection");
    }
});

// Get collection by id
cardCollectionRouter.get("/:id", isAuthenticated, async (req, res) => {
    try {
        const id = req?.params?.id;
        const query = { _id: new ObjectId(id) };
        const cardCollection = await collections?.cardCollections?.findOne(query);

        if (cardCollection) {
            res.status(200).send(cardCollection);
        } else {
            res.status(404).send(`Failed to find the card collection with ID: ${id}`);
        }
    } catch (error) {
        res.status(404).send(`Failed to find the card collection with ID: ${req?.params?.id}`);
    }
});

// Delete collection
cardCollectionRouter.delete("/:collectionId", isAuthenticated, async (req, res) => {
    try {
        const user = req.user as User;
        const id = new ObjectId(req?.params?.collectionId);

        const hasPermission = await checkPermission(user, id);

        if (!hasPermission) {
            res.status(403).send("You do not have permission to delete this collection");
            return;
        }

        const response = await collections?.cardCollections?.deleteOne({ _id: id });
        await collections?.cards?.deleteOne({ _id: id });

        res.status(200).send(response);
    } catch (error) {
        res.status(500).send(error instanceof Error ? error.message : "Unknown error");
    }
});

// Update existing collection
cardCollectionRouter.patch("/:collectionId", isAuthenticated, async (req, res) => {
    try {
        const user = req.user as User;
        const id = new ObjectId(req?.params?.collectionId);

        const hasPermission = await checkPermission(user, id);

        if (!hasPermission) {
            res.status(403).send("You do not have permission to update this collection");
            return;
        }

        const { title, summary, visibility } = req.body;

        const response = await collections?.cardCollections?.updateOne(
            {
                _id: id,
            },
            {
                $set: {
                    title: title,
                    summary: summary,
                    visibility: visibility,
                },
            }
        );

        res.status(200).send(response);
    } catch (error) {
        res.status(500).send(error instanceof Error ? error.message : "Unknown error");
    }
});

// Like/unlike collection
cardCollectionRouter.post("/like", isAuthenticated, async (req, res) => {
    try {
        const userId = (req.user as User)._id!.toString();
        const { id, isLiked } = req.body;

        if (isLiked) {
            const response = await collections?.likedCollections?.updateOne(
                { _id: new ObjectId(id) },
                { $pull: { likedBy: userId } }
            );
            res.status(200).send(response);
        } else {
            const response = await collections?.likedCollections?.updateOne(
                { _id: new ObjectId(id) },
                { $addToSet: { likedBy: userId } },
                { upsert: true }
            );
            res.status(200).send(response);
        }
    } catch (error) {
        res.status(500).send(error instanceof Error ? error.message : "Unknown error");
    }
});

// Get owner avatar
cardCollectionRouter.get("/ownerAvatar/:ownerId", isAuthenticated, async (req, res) => {
    try {
        const ownerId = new ObjectId(req?.params?.ownerId);

        const user = await collections?.users?.findOne(
            { _id: ownerId },
            { projection: { "profile.avatarUrl": 1, _id: 0 } }
        );

        const avatarUrl: string | undefined = user?.profile?.avatarUrl;

        res.status(200).send(avatarUrl);
    } catch (error) {
        res.status(500).send(error instanceof Error ? error.message : "Unknown error");
    }
});

export const checkPermission = async (user: User, id: ObjectId): Promise<boolean> => {
    // Fetch the collection to check ownership
    const collection = await collections?.cardCollections?.findOne({ _id: id });

    if (!collection) {
        return false;
    }

    // Check permissions
    const isOwner = collection.ownerId?.toString() === user._id?.toString();
    const isModeratorOrAdmin = user.role === "moderator" || user.role === "admin";

    if (!isOwner && !isModeratorOrAdmin) {
        return false;
    }

    return true;
};

import * as express from "express";
import { collections } from "../database";
import { isAuthenticated } from "./auth.routes";
import { User } from "../models/user";

// Responsible for the endpoints regarding multiple card collections
export const cardCollectionsRouter = express.Router();
cardCollectionsRouter.use(express.json());

// Get all owned collections
cardCollectionsRouter.get("/owned", isAuthenticated, async (req, res) => {
    try {
        const userId = (req.user as User)._id;
        const cardCollections = await collections?.cardCollections
            ?.find({ ownerId: userId })
            .toArray();
        res.status(200).send(cardCollections);
    } catch (error) {
        res.status(500).send(error instanceof Error ? error.message : "Unknown error");
    }
});

// Get all foreign (not owned, public) collections
cardCollectionsRouter.get("/foreign", isAuthenticated, async (req, res) => {
    try {
        const userId = (req.user as User)._id;
        const cardCollections = await collections?.cardCollections
            ?.find({ ownerId: { $ne: userId }, visibility: "public" })
            .toArray();
        res.status(200).send(cardCollections);
    } catch (error) {
        res.status(500).send(error instanceof Error ? error.message : "Unknown error");
    }
});

// Get all liked collection
cardCollectionsRouter.get("/liked", isAuthenticated, async (req, res) => {
    try {
        const userId = (req.user as User)._id?.toString();

        const likedCollections = await collections?.likedCollections
            ?.find({ likedBy: userId }, { projection: { _id: 1 } })
            .toArray();

        if (likedCollections) {
            const likedCollectionIds = likedCollections.map((c) => c._id);
            res.status(200).send(likedCollectionIds);
        } else {
            res.status(500).send("Failed to query liked collections");
        }
    } catch (error) {
        res.status(500).send(error instanceof Error ? error.message : "Unknown error");
    }
});

import * as express from "express";
import { isAuthenticated } from "./auth.routes";
import { ObjectId } from "mongodb";
import { collections } from "../database";
import { createPublicUser, User } from "../models/user";

export const profileRouter = express.Router();
profileRouter.use(express.json());

// Returns a users profile
profileRouter.get("/:id", isAuthenticated, async (req, res) => {
    try {
        const id = new ObjectId(req?.params?.id);
        const user = await collections?.users?.findOne({ _id: id });

        if (user) {
            const publicUser = createPublicUser(user);
            res.status(200).send(publicUser);
        } else {
            res.status(500).send("Failed to fetch user profile");
        }
    } catch (error) {
        res.status(500).send(error instanceof Error ? error.message : "Unknown error");
    }
});

// Deletes the logged in user's profile
profileRouter.delete("/:id", isAuthenticated, async (req, res) => {
    try {
        const id = new ObjectId(req?.params?.id);
        const user = req.user as User;

        if (!checkPermission(user, id)) {
            res.status(403).send("You don't have permission to do this");
            return;
        }

        const collectionIds = await collections?.cardCollections
            ?.find({ ownerId: id })
            .project<{ _id: ObjectId }>({ _id: 1 })
            .map((c) => c._id)
            .toArray();
        await collections?.users?.deleteOne({ _id: id });
        await collections?.cardCollections?.deleteMany({ ownerId: id });
        await collections?.cards?.deleteMany({
            collectionId: { $in: collectionIds },
        });

        res.status(200).send("Successfully deleted everything tied to this");
    } catch (error) {
        res.status(500).send(error instanceof Error ? error.message : "Unknown error");
    }
});

// Update profile
profileRouter.patch("/:id", isAuthenticated, async (req, res) => {
    try {
        const userId = new ObjectId(req?.params?.id);
        const user = req.user as User;

        if (!checkPermission(user, userId)) {
            res.status(403).send({ errorMessage: "You don't have permission to do this" });
            return;
        }

        const { username, email, bio, avatarUrl } = req.body.editProfileForm;

        // check if email or username is already taken
        const existingUser = await collections.users?.findOne({
            $or: [{ username: username }, { email: email }],
        });

        if (existingUser && !existingUser._id.equals(userId)) {
            if (existingUser.profile.username === username) {
                res.status(409).send({ errorMessage: "Username already taken" });
            } else {
                res.status(409).send({ errorMessage: "An account already exists with this email address" });
            }
            return;
        }

        const response = await collections?.users?.updateOne(
            { _id: userId },
            {
                $set: {
                    email: email,
                    "profile.username": username,
                    "profile.avatarUrl": avatarUrl,
                    "profile.bio": bio,
                },
            }
        );

        res.status(200).send({ successMessage: "Profile updated" });
    } catch (error) {
        res.status(500).send(error instanceof Error ? error.message : { errorMessage: "Unknown error" });
    }
});

export const checkPermission = async (user: User, id: ObjectId): Promise<boolean> => {
    if (user._id !== id) {
        return false;
    }

    return true;
};

import * as express from "express";
import { collections } from "../database";
import { User } from "../models/user";
import { ObjectId } from "mongodb";

// Responsible for the endpoints regarding admin methods
export const adminRouter = express.Router();
adminRouter.use(express.json());

// Get all users
adminRouter.get("/users", isAuthenticatedAdmin, async (_req, res) => {
    try {
        const users = await collections?.users
            ?.aggregate([
                {
                    $addFields: {
                        roleOrder: {
                            $switch: {
                                branches: [
                                    { case: { $eq: ["$role", "admin"] }, then: 0 },
                                    { case: { $eq: ["$role", "moderator"] }, then: 1 },
                                    { case: { $eq: ["$role", "user"] }, then: 2 },
                                ],
                                default: 3,
                            },
                        },
                    },
                },
                { $sort: { roleOrder: 1 } },
            ])
            .toArray();

        res.status(200).send(users);
    } catch (error) {
        res.status(500).send(error instanceof Error ? error.message : "Unknown error");
    }
});

adminRouter.post("/changeRole", isAuthenticatedAdmin, async (req, res) => {
    try {
        const { userId, role } = req.body;

        const response = await collections?.users?.updateOne(
            { _id: new ObjectId(userId) },
            {
                $set: {
                    role: role,
                },
            }
        );

        res.status(200).send(response);
    } catch (error) {
        res.status(500).send(error instanceof Error ? error.message : "Unknown error");
    }
});

adminRouter.delete("/deleteUser/:id", isAuthenticatedAdmin, async (req, res) => {
