    this.http
      .delete(`${this.adminUrl}/deleteUser/${userId}`, {
        withCredentials: true,
      })
      .subscribe({
        next: (response) => {
          this.fetchUsers();
          console.log('Successfully deleted user: ', response);
        },
        error: (error) => {
          console.log('User delete unsuccessful: ', error);
        },
      });
  }
