    .checkIsAuthenticated()
    .pipe(
      map((isAuthenticated) => {
        if (!isAuthenticated) {
          router.navigateByUrl('/login');
          return false;
        }
        return true;
      }),
      catchError((error) => {
        console.log(error);
        router.navigateByUrl('/login');
        return of(false);
      })
    );
};

